def count_ext(spec: dict) -> int {
    repo = Repo();
    for folder in spec["folders"] {
        fo = Folder(name=str(folder["name"]));
        repo ++> fo;
        for (fname, size) in folder["files"] {
            fo ++> File(name=str(fname), size=int(size));
        }
    }
    return (repo spawn ExtCount(ext=str(spec["ext"]))).total;
}

