def tree_size(spec: dict) -> int:
    """Total size in bytes of every file in the nested directory tree."""
    total = 0
    stack = [spec["tree"]]
    while stack:
        d = stack.pop()
        for _, size in d["files"]:
            total += size
        stack.extend(d["dirs"])
    return total

