def lang_report(spec: dict) -> str:
    """Per-extension byte totals for the whole tree, sorted by extension."""
    totals = {}
    stack = [spec["tree"]]
    while stack:
        d = stack.pop()
        for fname, size in d["files"]:
            if "." in fname:
                ext = fname.rsplit(".", 1)[1]
            else:
                ext = "plain"
            totals[ext] = totals.get(ext, 0) + size
        stack.extend(d["dirs"])
    parts = []
    for ext in sorted(totals):
        parts.append(ext + "=" + str(totals[ext]))
    return ", ".join(parts)

