        else { ext = "plain"; }
        self.totals[ext] = self.totals.get(ext, 0) + here.size;
    }
    can fmt with exit {
        parts: list = [];
        for ext in sorted(self.totals.keys()) {
            parts.append(ext + "=" + str(self.totals[ext]));
        }
        self.report = ", ".join(parts);
    }
}

