def first_fail(spec: dict) -> str {
    runner = Runner();
    prev = runner;
    for r in spec["results"] {
        res = Result(name=str(r["name"]), status=str(r["status"]));
        prev ++> res;
        prev = res;
    }
    return (runner spawn FirstFail()).found;
}

