def failure_tail(spec: dict) -> list:
    """The last k failing result names, in run order."""
    fails = [r["name"] for r in spec["results"] if r["status"] != "ok"]
    k = spec["k"]
    if k <= 0:
        return []
    start = len(fails) - k
    if start < 0:
        start = 0
    return fails[start:]

