def sniff_lang(spec: dict) -> str:
    """Best-scoring language for the text; ties alphabetical, no match is unknown."""
    scores = {}
    for r in spec["rules"]:
        if r["token"] in spec["text"]:
            scores[r["lang"]] = scores.get(r["lang"], 0) + r["weight"]
    best = "unknown"
    best_score = 0
    for lang in sorted(scores):
        if scores[lang] > best_score:
            best = lang
            best_score = scores[lang]
    return best

