def orphan_pages(spec: dict) -> list:
    """Alphabetical list of pages unreachable from the start page."""
    adj = {p: [] for p in spec["pages"]}
    for src, dst in spec["links"]:
        if src in adj and dst in adj:
            adj[src].append(dst)
    seen = set()
    stack = [spec["start"]]
    while stack:
        p = stack.pop()
        if p in seen or p not in adj:
            continue
        seen.add(p)
        stack.extend(adj[p])
    return sorted(p for p in spec["pages"] if p not in seen)

